// Handle both direct webhook and sub-workflow calls
const raw = $input.first().json;
const data = raw.body || raw;
const { ideaPrompt = '', briefId = '' } = data;

// Build competitive search queries
const baseIdea = ideaPrompt.slice(0, 100);
const queries = [
  `${baseIdea} competitors alternatives`,
  `${baseIdea} market analysis comparison`,
  `best ${baseIdea} tools software 2025 2026`
];

return queries.map(q => ({ json: { query: q, briefId } }));

// Process Google HTML search results for competitive analysis
const allSources = [];

for (const item of $input.all()) {
  const body = typeof item.json === 'string' ? item.json : (item.json?.body || item.json?.data || JSON.stringify(item.json));
  const html = typeof body === 'string' ? body : '';

  // Extract links from Google search results
  const matches = html.match(/<a[^>]*href="\/url\?q=([^&"]+)[^"]*"[^>]*>/g) || [];

  for (const match of matches.slice(0, 8)) {
    const urlMatch = match.match(/q=([^&"]+)/);
    if (!urlMatch) continue;

    let url = decodeURIComponent(urlMatch[1]);
    if (!url.startsWith('http')) continue;
    if (url.includes('google.com') || url.includes('youtube.com') || url.includes('accounts.google')) continue;

    // Extract domain as title
    let domain = '';
    try { domain = new URL(url).hostname.replace('www.', ''); } catch {}

    allSources.push({
      sourceType: 'webpage',
      url,
      title: `${domain} — competitive result`.slice(0, 500),
      snippet: `Found via competitive analysis search for related products and alternatives`,
      trustScore: 45,
      rawPayload: {
        source: 'n8n',
        workflowType: 'competitive_analysis'
      }
    });
  }
}

// Deduplicate by URL
const seen = new Set();
const unique = allSources
  .filter(s => s.url)
  .filter(s => {
    if (seen.has(s.url)) return false;
    seen.add(s.url);
    return true;
  })
  .slice(0, 8);

return [{ json: {
  sources: unique,
  metadata: {
    workflowName: 'nexus-competitive-analysis',
    totalResults: allSources.length,
    uniqueSources: unique.length
  }
}}];
